def perceive(data):
    text = data if isinstance(data, str) else str(data)
    fields = {}
    for line in text.splitlines():
        if ":" in line:
            k, v = line.split(":", 1)
            fields[k.strip().lower()] = v.strip()
    risky = fields.get("risky_clauses", "")
    flagged = [c for c in risky.replace(",", " ").split() if c]
    raw_total = fields.get("clauses_total", "")
    total = int(raw_total) if raw_total.isdigit() else max(len(flagged), 5)
    flags = len(flagged)
    if flags > total:
        total = flags
    return {"clauses_total": total, "flags_open": flags}
